params.script:
var r = $runner.getModuleResult("患者_電話番号再確認");
// 入力値から数字以外を除去（ハイフンなどの記号を削除）
var d = r ? String(r).replace(/[^0-9]/g, "") : ""; 
var res = "";

// 携帯電話の先頭番号（060, 070, 080, 090）をチェック
var isMobilePrefix = /^(060|070|080|090)/.test(d);

if (isMobilePrefix) {
    // 【ケース1】携帯電話番号の場合：読み上げ用SSMLを作成
    var m = ["ぜろ", "いち", "にい", "さん", "よん", "ごお", "ろく", "なな", "はち", "きゅう"];
    var ssml = "<speak>";
    
    for (var i = 0; i < d.length; i++) {
        var n = parseInt(d.charAt(i), 10);
        if (!isNaN(n)) {
            ssml += "<sub alias='" + m[n] + "'>" + d.charAt(i) + "</sub>";
            // 3桁目と7桁目の後に「の」とポーズ（300ms）を挿入
            if (i == 2 || i == 6) {
                ssml += " \u306E <break time='300ms'/> ";
            }
        }
    }
    ssml += "</speak>";
    res = ssml;
} else {
    // 【ケース2】上記以外の番号（固定電話など）の場合：NO_RESULTを返す
    res = "NO_RESULT";
}

// 最終的な結果を変数（#data#）に格納
$runner.setResult(res);
